import{_ as o,C as n,o as l,c as s,E as e,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const C=JSON.parse('{"title":"Moving to Croatia","description":"Immigration pathways and relocation guide for Croatia","frontmatter":{"layout":"doc","title":"Moving to Croatia","description":"Immigration pathways and relocation guide for Croatia"},"headers":[],"relativePath":"europe/croatia/moving-there.md","filePath":"europe/croatia/moving-there.md","lastUpdated":null}'),h={name:"europe/croatia/moving-there.md"};function g(m,t,c,u,f,p){const a=n("Badge");return l(),s("div",null,[e(a,{variant:"green"},{default:r(()=>[...t[0]||(t[0]=[i("EU Free Movement",-1)])]),_:1}),e(a,{variant:"yellow"},{default:r(()=>[...t[1]||(t[1]=[i("Non-EU Work Permits",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-croatia" tabindex="-1">Moving to Croatia <a class="header-anchor" href="#moving-to-croatia" aria-label="Permalink to &quot;Moving to Croatia&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Croatia grants full <strong>free movement rights</strong> to EU/EEA/Swiss citizens:</p><ul><li><strong>Up to 3 months</strong>: No registration required</li><li><strong>Over 3 months</strong>: Must register with the Ministry of Interior for a <strong>boravak</strong> (residence certificate)</li><li><strong>Requirements</strong>: Valid passport, proof of employment, sufficient funds, or health insurance</li><li><strong>Right to work</strong>: Automatic</li><li><strong>After 5 years</strong>: Eligible for permanent residence</li></ul><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Employment with Croatian employer</td><td>Job offer, work permit application by employer</td><td>1 year, renewable</td></tr><tr><td>EU Blue Card</td><td>Highly qualified workers</td><td>Degree + salary threshold (€40,000+/year)</td><td>2 years, renewable</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family of Croatian resident</td><td>Relationship proof, accommodation, income</td><td>1 year, renewable</td></tr><tr><td>Business Visa</td><td>Self-employment</td><td>Business registration, sufficient funds</td><td>1 year, renewable</td></tr></tbody></table><h3 id="digital-nomad-visa" tabindex="-1">Digital Nomad Visa <a class="header-anchor" href="#digital-nomad-visa" aria-label="Permalink to &quot;Digital Nomad Visa&quot;">​</a></h3><p>Croatia offers one of the best <strong>Digital Nomad Visas</strong> in Europe:</p><ul><li>Valid for <strong>up to 12 months</strong> (non-renewable)</li><li>Must work for a company outside Croatia</li><li>Income requirement: €2,500+/month (approximate)</li><li>No Croatian tax liability</li><li>Cannot be extended beyond 12 months</li><li>Cannot switch to a regular work permit without leaving Croatia</li><li>Allows bringing family members</li><li>Popular option for remote workers</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa/Residence</strong>: Check requirements for your nationality</li><li>[ ] <strong>Health Insurance</strong>: EU citizens: EHIC card; others: private insurance required</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (English or Croatian)</li><li>[ ] <strong>Medical Records</strong>: Translated into Croatian</li><li>[ ] <strong>Banking</strong>: International banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (njuskalo.hr, crozilla.com)</li><li>[ ] <strong>Language</strong>: Basic Croatian very helpful</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] <strong>Register residence</strong> with the local police (MUP) within 30 days</li><li>[ ] <strong>Apply for boravak</strong> (residence certificate) for stays over 3 months</li><li>[ ] <strong>Get OIB</strong> (personal identification number) — required for everything</li><li>[ ] <strong>Register with HZZO</strong> (Croatian Health Insurance Fund)</li><li>[ ] <strong>Open bank account</strong> — Zagrebačka banka, PBZ, Erste</li><li>[ ] <strong>Get Croatian phone number</strong> — Hrvatski Telekom, A1, Telemach</li><li>[ ] <strong>Connect with TransAid Croatia</strong> or similar organizations</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Zagreb</th><th>Split</th><th>Smaller Cities</th></tr></thead><tbody><tr><td>Rent (1-bedroom)</td><td>€400-700/month</td><td>€350-600/month</td><td>€250-450/month</td></tr><tr><td>Groceries</td><td>€200-350/month</td><td>€200-300/month</td><td>€180-280/month</td></tr><tr><td>Utilities</td><td>€100-200/month</td><td>€100-180/month</td><td>€80-150/month</td></tr><tr><td>Public transport</td><td>€40-60/month</td><td>€30-50/month</td><td>€20-40/month</td></tr><tr><td>Eating out</td><td>€8-15/meal</td><td>€8-15/meal</td><td>€6-12/meal</td></tr></tbody></table><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li><strong>Official language</strong>: Croatian (South Slavic)</li><li><strong>English</strong>: Widely spoken among young people, especially in Zagreb and tourist areas</li><li><strong>German</strong>: Also relatively common</li><li><strong>Integration</strong>: Learning Croatian is important for long-term settlement</li><li>Free Croatian courses available for refugees and some immigrants</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Mediterranean coast</strong>: Hot summers, mild winters (Split, Dubrovnik, Rijeka)</li><li><strong>Continental inland</strong>: Cold winters, warm summers (Zagreb, Osijek)</li><li><strong>Summer</strong>: 25°C to 35°C (coast), 20°C to 30°C (inland)</li><li><strong>Winter</strong>: 5°C to 10°C (coast), -5°C to 5°C (inland)</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>Zagreb is the most trans-friendly</strong> city</li><li>Rijeka and Split are moderately tolerant</li><li>Rural areas and islands are very conservative</li><li>Trans healthcare is very limited — plan for accessing care abroad</li><li><strong>TransAid Croatia</strong> provides community support</li><li>Pride events in Zagreb, Rijeka, Split, and Osijek</li><li>EU membership provides some legal protections</li><li>Growing expat community, especially in Zagreb and along the coast</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://mup.gov.hr/" target="_blank" rel="noreferrer">MUP - Ministry of Interior</a></li><li><a href="https://www.hzzo.hr/" target="_blank" rel="noreferrer">HZZO - Croatian Health Insurance Fund</a></li><li><a href="https://www.njuskalo.hr/" target="_blank" rel="noreferrer">Njuskalo - Housing</a></li><li><a href="https://croatia.hr/en-GB/plan/digital-nomad" target="_blank" rel="noreferrer">Digital Nomad Visa - Croatia</a></li><li><a href="https://transaid.hr/" target="_blank" rel="noreferrer">TransAid Croatia</a></li><li><a href="https://zagreb-pride.net/" target="_blank" rel="noreferrer">Zagreb Pride</a></li></ul>',26))])}const y=o(h,[["render",g]]);export{C as __pageData,y as default};
